    public static boolean ubsCheckPeriodIsOpened(TransDate _accountingDate)
    {
        RecId                   calendarRecId;
        boolean                 ret;
        FiscalCalendarPeriod    fiscalCalendarPeriod;

        calendarRecId = Ledger::fiscalCalendar(CompanyInfo::current());
            
        fiscalCalendarPeriod = LedgerFiscalCalendar::findPeriodByPeriodCodeDate(calendarRecId,
                                                                                _accountingDate,
                                                                                FiscalPeriodType::Operating);

        return fiscalCalendarPeriod.currentLedgerPeriodStatus() == FiscalPeriodStatus::Open;
    }
